import{_ as e,o,c as r,ai as s}from"./chunks/framework.CaiDwmc7.js";const _=JSON.parse('{"title":"场景实战：如何用设计模式重构烂代码","description":"","frontmatter":{},"headers":[],"relativePath":"design-patterns/scenario.md","filePath":"design-patterns/scenario.md"}'),n={name:"design-patterns/scenario.md"};function i(a,t,l,g,c,p){return o(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="场景实战-如何用设计模式重构烂代码" tabindex="-1">场景实战：如何用设计模式重构烂代码 <a class="header-anchor" href="#场景实战-如何用设计模式重构烂代码" aria-label="Permalink to “场景实战：如何用设计模式重构烂代码”">​</a></h1><hr><h3 id="❓-面试官-如果接手一个老项目-里面有个上千行的类-充满了各种-if-else-和重复的-屎山-代码-你会怎么用设计模式去重构它-【中高级】" tabindex="-1">❓ 面试官：如果接手一个老项目，里面有个上千行的类，充满了各种 if-else 和重复的“屎山”代码，你会怎么用设计模式去重构它？【中高级】 <a class="header-anchor" href="#❓-面试官-如果接手一个老项目-里面有个上千行的类-充满了各种-if-else-和重复的-屎山-代码-你会怎么用设计模式去重构它-【中高级】" aria-label="Permalink to “❓ 面试官：如果接手一个老项目，里面有个上千行的类，充满了各种 if-else 和重复的“屎山”代码，你会怎么用设计模式去重构它？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><blockquote><p>这是一个综合性极强的开放题。面试官不是想听你背设计模式定义，而是想看你的<strong>架构思维、重构胆量和落地套路</strong>。</p></blockquote><p><strong>💡 一句话总结（先抛结论）：</strong> 重构千万行烂代码，绝不是一上来就大拆大改。我的整体策略是：<strong>先用单测兜底保平安，再通过“提取公共方法 -&gt; 策略+工厂干掉 if-else -&gt; 模板方法固化流程 -&gt; 责任链拆分解耦”的组合拳，小步快跑地完成重构。</strong></p><p><strong>📝 详细的高级重构剧本（面试王炸答法）：</strong></p><p><strong>第一阶段：防御性准备（极其展现高级工程师的成熟度）</strong> “面试官，在动刀子之前，我绝对不会直接改代码。老代码之所以是屎山，往往是因为它耦合了极其复杂的历史业务。</p><ol><li>我会先花时间梳理它的核心逻辑。</li><li><strong>编写覆盖主流场景的单元测试</strong>。有了单元测试这个安全网兜底，我才敢保证我的重构不会引发线上 P0 级事故。”</li></ol><p><strong>第二阶段：初级重构——减肥与去重</strong></p><ol><li><strong>胖方法瘦身</strong>：一个方法写了 800 行，我会把它按业务功能拆分成 10 个 <code>private</code> 方法。让主方法变成一个读起来像讲故事一样的骨架。</li><li><strong>提取工具类</strong>：把里面重复粘贴的时间处理、正则匹配、格式转换等代码，抽离到 <code>Utils</code> 类里。这能先砍掉 30% 左右的废话代码。</li></ol><p><strong>第三阶段：中级重构——消灭又臭又长的 if-else（策略模式 + 工厂模式）</strong> “如果这几百行代码是根据不同的业务类型（比如不同的发货渠道、不同的会员等级）在走不同的分支。”</p><ul><li>我会定义一个<strong>策略接口</strong>，然后为每一个大的 <code>if</code> 分支新建一个实现类。</li><li>接着用一个<strong>工厂类（结合 Spring 的 Map 注入）</strong>来管理这些策略。</li><li>最终，主类里那几百行的 <code>if-else</code> 就被缩减成了两行：<code>Strategy strategy = Factory.get(type); strategy.execute();</code></li></ul><p><strong>第四阶段：高级重构——固化流程与复杂校验解耦（模板方法 + 责任链模式）</strong></p><ul><li><strong>模板方法模式</strong>：如果这些策略类里，大部分的流程是一样的（比如都是『先验签 -&gt; 再查库 -&gt; 个性化计算 -&gt; 写回库』），仅仅是个性化计算不同。我会搞一个<strong>抽象父类</strong>把这个骨架定死（<code>final</code>），大家都继承父类，只实现自己不同的那一步。</li><li><strong>责任链模式</strong>：如果老代码里有一大串的校验逻辑（比如下单前要校验黑名单、校验库存、校验优惠券、校验风控），堆在一起极其恶心。我会把每个校验写成一个个独立的 Filter（拦截器）。通过责任链把它们串起来，如果后续要增加新的校验规则，只要加个 Filter 插进去就行，老校验逻辑一点不用改。</li></ul><p><strong>🔥 最终总结：</strong> &quot;经过这一套组合拳，原本上千行的、毫无可读性的『上帝类』，就被打散成了一个个<strong>职责单一、易于测试、完美符合开闭原则</strong>的小类。虽然类的数量变多了，但代码的维护成本成倍下降。&quot;</p>',16)])])}const f=e(n,[["render",i]]);export{_ as __pageData,f as default};
